module sr_latch (  
    input wire Anti_S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (Anti_S or R) begin  
        if (Anti_S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (!Anti_S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end else if (Anti_S && R) begin  
            // Undefined state  
        end  
    end  
endmodule
